479→/**
480→ * Create a process-like object that intercepts stdout/stderr writes
481→ * and records them as side effects.
482→ */
483→function createCapturingProcess(sideEffects: SideEffect[]): typeof process {
484→  const makeStreamWriter = (level: string) => {
485→    const originalStream = level === "stdout" ? process.stdout : process.stderr;
486→    return new Proxy(originalStream, {
487→      get(target, prop) {
488→        if (prop === "write") {
489→          return (chunk: string | Uint8Array, ...rest: unknown[]): boolean => {
490→            const text = typeof chunk === "string" ? chunk : new TextDecoder().decode(chunk);
491→            const trimmed = text.replace(/\n$/, "");
492→            if (trimmed.length > 0) {
493→              const message = truncateMessage(trimmed);
494→              sideEffects.push({ kind: "console_output", level, message });
495→            }
496→            return true;
497→          };
498→        }
499→        const val = Reflect.get(target, prop, target);
500→        return typeof val === "function" ? val.bind(target) : val;
501→      },
502→    });
503→  };
504→
505→  return new Proxy(process, {
506→    get(target, prop) {
507→      if (prop === "stdout") return makeStreamWriter("stdout");
508→      if (prop === "stderr") return makeStreamWriter("stderr");
509→      const val = Reflect.get(target, prop, target);
510→      return typeof val === "function" ? val.bind(target) : val;
511→    },
512→  });
513→}
