515→/**
516→ * Execute a function with the given inputs and capture the result.
517→ */
518→export async function executeFunction(
519→  filePath: string,
520→  functionRef: string,
521→  inputs: unknown[],
522→): Promise<RawExecuteResult> {
523→  const fn = resolveFunction(filePath, functionRef);
524→
525→  const sideEffects: SideEffect[] = [];
526→  const previousTarget = consoleTarget;
527→  consoleTarget = createCapturingConsole(sideEffects);
528→
529→  let metrics: MeasuredExecution;
530→  try {
531→    const reconstructedInputs = inputs.map(reconstructValue);
532→    metrics = await measureExecution(() => fn(...reconstructedInputs));
533→  } finally {
534→    consoleTarget = previousTarget;
535→  }
536→
537→  if (metrics.thrownError) {
538→    sideEffects.push({
539→      kind: "thrown_error",
540→      error_type: metrics.thrownError.error_type,
541→      message: metrics.thrownError.message,
542→      stack: metrics.thrownError.stack,
543→    });
544→  }
545→
546→  return {
547→    return_value: metrics.returnValue ?? null,
548→    thrown_error: metrics.thrownError,
549→    side_effects: sideEffects,
550→    branch_path: [],
551→    path_constraints: [],
552→    lines_executed: [],
553→    performance: metrics.performance,
554→    calls_to_external: [],
555→    scope_events: [],
556→  };
557→}
