    FunctionNotFound,
    /// Syntax or parse error in source file.
    ParseError,
    /// Instrumentation failed.
    InstrumentationFailed,
    /// Execution timed out.
    ExecutionTimeout,
    /// Execution crashed (segfault, OOM, etc.).
    ExecutionCrash,
    /// Protocol version mismatch.
