        }),
        (arb_ident(), arb_setup_level())
            .prop_map(|(scope, level)| Command::Teardown { scope, level }),
        (arb_ident(), arb_ident(), arb_generator_kind()).prop_map(|(file, name, kind)| {
            Command::Generate {
                file,
                name,
                kind,
                recipe: None,
                project_root: None,
