        Just(BinOpKind::Div),
        Just(BinOpKind::Mod),
        Just(BinOpKind::And),
        Just(BinOpKind::Or),
        Just(BinOpKind::BitwiseAnd),
        Just(BinOpKind::BitwiseOr),
        Just(BinOpKind::BitwiseXor),
        Just(BinOpKind::Shl),
        Just(BinOpKind::Shr),
        Just(BinOpKind::BitClear),
        Just(BinOpKind::In),
        Just(BinOpKind::InstanceOf),
    ]
}

