const arbRequest: fc.Arbitrary<Request> = fc.oneof(
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    command: fc.constant("handshake" as const),
    capabilities: fc.array(arbIdent, { maxLength: 3 }),
