const arbResponse: fc.Arbitrary<Response> = fc.oneof(
  fc.record({
    protocol_version: fc.constant(PROTOCOL_VERSION),
    id: fc.nat(1000),
    status: fc.constant("handshake" as const),
    frontend_version: fc.constant(PROTOCOL_VERSION),
